consumption.cssSetup:
Import tokens CSS at your app entry point: import '@ds-mo/tokens/css';
This provides all var(--color-*), var(--dimension-*), var(--effect-*), and var(--typography-*) custom properties.
For dark mode, set data-theme="dark" on <html>.

files.content:
.bannerWrapper {}

.banner {
  position: relative;
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

.bannerHeaderSurface {
  width: 100%;
  height: var(--dimension-space-100);
  flex-shrink: 0;
  overflow: hidden;
  border-bottom: var(--dimension-stroke-width-015) solid var(--color-border-primary);
}

.bannerHeader {
  width: 100%;
  height: 100%;
  background: repeating-linear-gradient(
    -45deg,
    var(--banner-content),
    var(--banner-content) var(--dimension-size-100),
    transparent var(--dimension-size-100),
    transparent var(--dimension-size-200)
  );
}

.bannerBody {
  padding: var(--dimension-space-075);
  min-height: var(--dimension-size-400);
  display: flex;
  align-items: flex-start;
  gap: var(--dimension-space-075);
}

.message {
  color: var(--banner-content);
  line-height: var(--typography-lineheight-md);
  display: block;
  flex: 1;
  min-width: 0;
}

.dismiss {
  background: none;
  border: none;
  margin: 0;
  padding: var(--dimension-space-025);
  color: var(--banner-content);
  cursor: pointer;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  border-radius: var(--dimension-radius-050);
  position: relative;
}

.dismiss::before {
  content: '';
  position: absolute;
  inset: 0;
  border-radius: inherit;
  background-color: transparent;
  transition: var(--effect-transition-interaction-background-short-2);
  pointer-events: none;
}

.dismiss:hover::before  { background-color: var(--color-interaction-hover); }
.dismiss:active::before { background-color: var(--color-interaction-pressed); }

.dismiss:focus-visible {
  outline: var(--dimension-stroke-width-025) solid var(--color-interaction-focus);
  outline-offset: var(--dimension-stroke-width-015);
}

.floatingPosition {
  position: fixed;
  top: var(--dimension-space-200);
  left: 50%;
  transform: translateX(-50%);
  pointer-events: none;
}

.floatingToast {
  backface-visibility: hidden;
  -webkit-font-smoothing: subpixel-antialiased;
  animation: toastFadeIn var(--effect-motion-short-2) forwards;
}

.floatingToast.closing {
  animation: toastFadeOut var(--effect-motion-short-3) forwards;
}

@keyframes toastFadeIn {
  from { opacity: 0; transform: translateY(-8px); }
  to { opacity: 1; transform: translateY(0); }
}

@keyframes toastFadeOut {
  from { opacity: 1; transform: translateY(0); }
  to { opacity: 0; transform: translateY(-4px); }
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { createPortal } from 'react-dom';
import { Cross } from '@ds-mo/icons';
import { Surface } from '@/components/Surface';
import { Text } from '@/components/Text';
import { getCssTimeMs } from '@/utils/css-tokens';
import styles from './Banner.module.css';

const TOAST_DURATION_FALLBACK_MS = 4000;
const FADE_OUT_DURATION_MS = 200;

export type BannerIntent =
  | 'brand' | 'positive' | 'negative' | 'warning' | 'caution'
  | 'ai' | 'neutral' | 'walkthrough' | 'guide';

export type BannerContrast = 'faint' | 'medium' | 'bold' | 'strong';

export interface BannerProps {
  intent: BannerIntent;
  contrast: BannerContrast;
  message: string;
  header?: boolean;
  className?: string;
  floating?: boolean;
  onDismiss?: () => void;
  /** Accessible label for the dismiss button. Defaults to "Dismiss". */
  dismissLabel?: string;
}

const getContentColorVar = (intent: BannerIntent, contrast: BannerContrast): string => {
  if (contrast === 'bold') return 'var(--color-foreground-on-bold-background-primary)';
  const contentContrast = contrast === 'faint' ? 'bold' : contrast === 'medium' ? 'strong' : 'medium';
  return `var(--color-foreground-${contentContrast}-${intent})`;
};

export const Banner: React.FC<BannerProps> = ({
  intent,
  contrast,
  message,
  header = false,
  className = '',
  floating = false,
  onDismiss,
  dismissLabel = 'Dismiss',
}) => {
  const toastDurationMs = getCssTimeMs('--effect-animation-delay-long-2', TOAST_DURATION_FALLBACK_MS);
  const messageColor = getContentColorVar(intent, contrast);
  const [isClosing, setIsClosing] = useState(false);
  const dismissTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const closeTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const beginClose = useCallback(() => {
    if (dismissTimerRef.current) clearTimeout(dismissTimerRef.current);
    if (closeTimerRef.current) clearTimeout(closeTimerRef.current);
    dismissTimerRef.current = null;
    if (floating) {
      setIsClosing(true);
      closeTimerRef.current = setTimeout(() => {
        closeTimerRef.current = null;
        onDismiss?.();
      }, FADE_OUT_DURATION_MS);
    } else {
      onDismiss?.();
    }
  }, [floating, onDismiss]);

  const scheduleDismiss = useCallback(() => {
    if (dismissTimerRef.current) clearTimeout(dismissTimerRef.current);
    dismissTimerRef.current = setTimeout(() => {
      dismissTimerRef.current = null;
      beginClose();
    }, toastDurationMs);
  }, [beginClose, toastDurationMs]);

  useEffect(() => {
    if (floating && message) scheduleDismiss();
    return () => {
      if (dismissTimerRef.current) clearTimeout(dismissTimerRef.current);
      if (closeTimerRef.current) clearTimeout(closeTimerRef.current);
    };
  }, [floating, message, scheduleDismiss]);

  const isAssertive = intent === 'negative';
  const role = isAssertive ? 'alert' : 'status';
  const ariaLive = isAssertive ? undefined : 'polite';

  const content = (
    <div
      className={`${styles.bannerWrapper} ${className}`.trim()}
      style={{ '--banner-content': messageColor } as React.CSSProperties}
      role={role}
      aria-live={ariaLive}
    >
      <Surface
        elevation={floating ? 'floating' : 'elevated'}
        intent={intent}
        contrast={contrast}
        radius="sm"
        className={styles.banner}
      >
        {header && (
          <div className={styles.bannerHeaderSurface}>
            <div className={styles.bannerHeader} aria-hidden />
          </div>
        )}
        <div className={styles.bannerBody}>
          <Text variant="text-body-medium" as="span" className={styles.message}>
            {message}
          </Text>
          {onDismiss && (
            <button
              type="button"
              className={styles.dismiss}
              onClick={beginClose}
              aria-label={dismissLabel}
            >
              <Cross size={16} />
            </button>
          )}
        </div>
      </Surface>
    </div>
  );

  if (floating) {
    return createPortal(
      <div className={styles.floatingPosition} style={{ zIndex: 9998 }}>
        <div className={`${styles.floatingToast} ${isClosing ? styles.closing : ''}`}>
          {content}
        </div>
      </div>,
      document.body
    );
  }

  return content;
};

Banner.displayName = 'Banner';
